mapper.select:
SELECT
    TBP.ID, TBP.POST_TITLE, TBP.POST_CONTENT, TBP.POST_READ_COUNT, TBP.MEMBER_ID,
    (
        SELECT COUNT(*)
        FROM TBL_POST_LIKE
        WHERE POST_ID = #{postId}
    ) POST_LIKE_COUNT,
    (
        SELECT COUNT(*)
        FROM TBL_POST_LIKE
        WHERE POST_ID = #{postId}
          AND MEMBER_ID = #{memberId}
    ) IS_CLICK
FROM TBL_POST TBP
WHERE TBP.ID = #{postId}
